import{_ as a,aa as n,o as r,c as t,a as i,V as k,U as l,Y as o}from"./chunks/framework.C09tu6ka.js";import"./chunks/theme.DESAuTfw.js";const b=JSON.parse('{"title":"Jenkins to Docker","description":"在 Docker 中部署 Jenkins CI 服务，包括数据持久化配置、Docker Socket 挂载和首次启动的初始化步骤","frontmatter":{"title":"Jenkins to Docker","category":["Docker"],"tag":["Jenkins","Docker run","Blue Ocean"],"description":"在 Docker 中部署 Jenkins CI 服务，包括数据持久化配置、Docker Socket 挂载和首次启动的初始化步骤","date":"2023-02-13T15:42:00.000Z","updated":"2023-02-13T15:42:00.000Z","cover":"devicon:jenkins"},"headers":[],"relativePath":"articles/devops/docker/run/jenkins.md","filePath":"articles/devops/docker/run/jenkins.md"}'),h={name:"articles/devops/docker/run/jenkins.md"};function d(c,e,p,F,u,C){const s=n("SmallCard");return r(),t("div",null,[e[0]||(e[0]=i("h2",{id:"参考资料",tabindex:"-1"},[k("参考资料 "),i("a",{class:"header-anchor",href:"#参考资料","aria-label":"Permalink to “参考资料”"},"​")],-1)),l(s,{cards:[{title:"安装jenkins",desc:"Jenkins – an open source automation server which enables developers around the world to reliably build, test, and deploy their software.",logo:"https://www.jenkins.io/apple-touch-icon.png",link:"https://www.jenkins.io/zh/doc/book/installing/"}]}),e[1]||(e[1]=o('<h2 id="环境" tabindex="-1">环境 <a class="header-anchor" href="#环境" aria-label="Permalink to “环境”">​</a></h2><p>1.lunix 2.docker</p><h3 id="创建文件夹" tabindex="-1">创建文件夹 <a class="header-anchor" href="#创建文件夹" aria-label="Permalink to “创建文件夹”">​</a></h3><blockquote><p>在适当位置创建如下文件夹,层级如下</p></blockquote><p>丨---jenkins 丨---丨---jenkins-data 丨---丨---jenkins</p><h3 id="执行-docker-run" tabindex="-1">执行 <code>docker run</code> <a class="header-anchor" href="#执行-docker-run" aria-label="Permalink to “执行 docker run”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --restart=always</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jenkinsci</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8080:8080</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 50000:50000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/localtime:/etc/localtime:ro</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tool/jenkins/jenkins-data:/var/jenkins_home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tool/jenkins/jenkins:/usr/share/jenkins</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/run/docker.sock:/var/run/docker.sock</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jenkinsci/blueocean:latest</span></span></code></pre></div><p>docker 命令解释:</p><ol><li>--restart=always 总是启动</li><li>-p 8080:8080 -p 50000:50000 端口映射</li><li>-v /etc/localtime:/etc/localtime:ro 时区</li><li>-v /tool/jenkins/jenkins-data:/var/jenkins_home jenkins数据,修改此文件夹内容需要重启jenkins</li><li>-v /tool/jenkins/jenkins:/usr/share/jenkins 挂载存放jenkins.war包文件,防止删除容器重启后回到jenkins之前版本,首次使用需要运行jenkins将该目录拷贝到宿主机</li><li>-v /var/run/docker.sock:/var/run/docker.sock</li></ol><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h3><p>首次运行docker run 不需要挂载<code>-v /tool/jenkins/jenkins:/usr/share/jenkins</code>,启动成功后,将文件夹/usr/share/jenkins下内容考到宿主机,停止并删除容器在重新运行<code>docker run</code>并添加此挂载<code>-v /tool/jenkins/jenkins:/usr/share/jenkins</code>,挂载改文件夹为保证jenkins的升级时，删除容器重新启动容器的时候保持原有配置不变</p><h3 id="后续" tabindex="-1">后续 <a class="header-anchor" href="#后续" aria-label="Permalink to “后续”">​</a></h3><p>安装设置向导根据<a href="https://www.jenkins.io/zh/doc/book/installing/" target="_blank" rel="noreferrer">官网</a>进行操作即可</p>',13))])}const m=a(h,[["render",d]]);export{b as __pageData,m as default};
